SELECT *
FROM user_relation
WHERE from_account_id = #{fromAccountId}
  AND to_account_id = #{toAccountId}
  AND relation_type = #{relationType}
LIMIT 1

SELECT EXISTS(
    SELECT 1
    FROM user_relation
    WHERE from_account_id = #{fromAccountId}
      AND to_account_id = #{toAccountId}
      AND relation_type = #{relationType}
      AND status = #{status}
)
